import{_ as s,o as e,c as t,ag as i}from"./chunks/framework.CMYkYJvz.js";const k=JSON.parse('{"title":"Desktop Installation and Build","description":"Desktop app installation, local build steps, and notes.","frontmatter":{"title":"Desktop Installation and Build","description":"Desktop app installation, local build steps, and notes.","editLink":false},"headers":[],"relativePath":"en/getting-started/desktop.md","filePath":"en/getting-started/desktop.md"}'),n={name:"en/getting-started/desktop.md"};function o(l,a,d,r,p,h){return e(),t("div",null,[...a[0]||(a[0]=[i(`<blockquote><p>This page is automatically synced from <code>docs-en/desktop.md</code>. Language: <strong>English</strong> | <a href="./../../getting-started/desktop">中文</a></p></blockquote><h1 id="desktop-installation-and-build" tabindex="-1">Desktop Installation and Build <a class="header-anchor" href="#desktop-installation-and-build" aria-label="Permalink to &quot;Desktop Installation and Build&quot;">​</a></h1><p>The desktop app is built with Tauri. The package includes Web assets and starts the bundled <code>bifrost</code> CLI backend inside the app.</p><h2 id="installation" tabindex="-1">Installation <a class="header-anchor" href="#installation" aria-label="Permalink to &quot;Installation&quot;">​</a></h2><h3 id="pick-the-right-installer" tabindex="-1">Pick the Right Installer <a class="header-anchor" href="#pick-the-right-installer" aria-label="Permalink to &quot;Pick the Right Installer&quot;">​</a></h3><p>Open <a href="https://github.com/bifrost-proxy/bifrost/releases" target="_blank" rel="noreferrer">GitHub Releases</a>, choose the latest release, and expand <code>Assets</code>. Desktop installer names include both platform and architecture:</p><table tabindex="0"><thead><tr><th>System</th><th>File</th><th>Device</th></tr></thead><tbody><tr><td>macOS Apple Silicon</td><td><code>bifrost-desktop-vX.X.X-aarch64-apple-darwin.dmg</code></td><td>M1/M2/M3/M4 and newer Apple Silicon Macs</td></tr><tr><td>macOS Intel</td><td><code>bifrost-desktop-vX.X.X-x86_64-apple-darwin.dmg</code></td><td>Intel Macs</td></tr><tr><td>Windows x64</td><td><code>bifrost-desktop-vX.X.X-x86_64-pc-windows-msvc.msi</code></td><td>Most Windows laptops and desktops</td></tr><tr><td>Windows ARM64</td><td><code>bifrost-desktop-vX.X.X-aarch64-pc-windows-msvc.msi</code></td><td>Windows on ARM devices</td></tr></tbody></table><p>If you only need the command line, install the CLI from <a href="./installation"><code>getting-started.md</code></a> instead.</p><h3 id="homebrew-cask-on-macos" tabindex="-1">Homebrew Cask on macOS <a class="header-anchor" href="#homebrew-cask-on-macos" aria-label="Permalink to &quot;Homebrew Cask on macOS&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">brew</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tap</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> bifrost-proxy/bifrost</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">brew</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --cask</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> bifrost-desktop</span></span></code></pre></div><h3 id="manual-installer" tabindex="-1">Manual Installer <a class="header-anchor" href="#manual-installer" aria-label="Permalink to &quot;Manual Installer&quot;">​</a></h3><p>Download desktop installers from <a href="https://github.com/bifrost-proxy/bifrost/releases" target="_blank" rel="noreferrer">GitHub Releases</a>.</p><h4 id="macos-dmg" tabindex="-1">macOS <code>.dmg</code> <a class="header-anchor" href="#macos-dmg" aria-label="Permalink to &quot;macOS \`.dmg\`&quot;">​</a></h4><ol><li>Download the <code>.dmg</code> that matches your Mac.</li><li>Open the <code>.dmg</code>.</li><li>Drag <code>Bifrost.app</code> to <code>Applications</code>.</li><li>Launch Bifrost from <code>Applications</code>, Launchpad, or Spotlight.</li><li>If macOS warns that the app was downloaded from the internet, confirm that you want to open it. If Gatekeeper blocks an unsigned build, allow it from <code>System Settings -&gt; Privacy &amp; Security</code>.</li></ol><h4 id="windows-msi" tabindex="-1">Windows <code>.msi</code> <a class="header-anchor" href="#windows-msi" aria-label="Permalink to &quot;Windows \`.msi\`&quot;">​</a></h4><ol><li>Download the <code>.msi</code> that matches your device architecture.</li><li>Double-click the <code>.msi</code> and follow the installer.</li><li>Launch <code>Bifrost</code> from the Start menu.</li><li>If Windows SmartScreen warns about an unknown publisher, continue only after confirming the file came from the official GitHub Releases page.</li></ol><h2 id="first-launch" tabindex="-1">First Launch <a class="header-anchor" href="#first-launch" aria-label="Permalink to &quot;First Launch&quot;">​</a></h2><p>After installation:</p><ul><li>Launch <code>Bifrost.app</code> on macOS.</li><li>Launch <code>Bifrost</code> from the Windows Start menu.</li><li>The desktop app starts the bundled <code>bifrost</code> backend inside the app, so you do not need to run <code>bifrost start</code> first.</li><li>The default data directory is <code>~/.bifrost</code>; desktop and CLI installs share config, certs, logs, and runtime state by default.</li><li>The first launch checks and installs the Bifrost CA asynchronously. For HTTPS inspection, confirm that the system trusts the Bifrost CA.</li><li>The desktop app checks for updates at startup and at most once every 6 hours. When a new version is available, it shows a notification and opens the update window.</li></ul><p>Set <code>BIFROST_DATA_DIR</code> before startup only when you need an isolated test environment or a multi-instance debugging setup.</p><h2 id="desktop-and-cli-together" tabindex="-1">Desktop and CLI Together <a class="header-anchor" href="#desktop-and-cli-together" aria-label="Permalink to &quot;Desktop and CLI Together&quot;">​</a></h2><p>The desktop app includes a bundled <code>bifrost</code> backend for its proxy, rules, traffic, and settings pages. You can also install the standalone CLI for terminals, scripts, CI, and AI coding tools.</p><p>If you installed the desktop app first, open desktop Settings and click <code>Install CLI &amp; Skills</code> in <code>Desktop Proxy Core</code>. This action:</p><ul><li>Installs the bundled <code>bifrost</code> CLI into the user command directory.</li><li>Installs Bifrost AI skills for Codex, Claude Code, Trae, Cursor, and other supported tools.</li><li>Keeps update semantics separate: desktop updates use <code>bifrost app upgrade</code>, while CLI updates use <code>bifrost upgrade</code>.</li></ul><h2 id="manage-the-desktop-app-from-cli" tabindex="-1">Manage the Desktop App from CLI <a class="header-anchor" href="#manage-the-desktop-app-from-cli" aria-label="Permalink to &quot;Manage the Desktop App from CLI&quot;">​</a></h2><p><code>bifrost app</code> manages desktop installers separately from CLI updates:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bifrost</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> app</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bifrost</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> app</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> upgrade</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bifrost</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> app</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> uninstall</span></span></code></pre></div><p><code>bifrost app upgrade</code> installs the latest desktop package. If it detects a standalone CLI, it can also update that CLI to the latest version. Updates triggered from the desktop UI use the same progress window for download, install, and restart.</p><p>The <code>Install CLI &amp; Skills</code> button is shown only in the Tauri desktop app. It is not shown in the browser-hosted CLI Web UI.</p><h2 id="update-and-uninstall" tabindex="-1">Update and Uninstall <a class="header-anchor" href="#update-and-uninstall" aria-label="Permalink to &quot;Update and Uninstall&quot;">​</a></h2><p>The desktop app checks for updates automatically. You can also manage it manually:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bifrost</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> app</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> upgrade</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bifrost</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> app</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> uninstall</span></span></code></pre></div><p>From a source checkout, the unified uninstall script can remove CLI and desktop artifacts:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./uninstall.sh</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./uninstall.sh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --purge</span></span></code></pre></div><p><code>--purge</code> removes local data, including rules, certs, logs, and runtime state. Use it only when you no longer need the existing configuration.</p><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><h3 id="macos-says-the-app-cannot-be-opened" tabindex="-1">macOS says the app cannot be opened <a class="header-anchor" href="#macos-says-the-app-cannot-be-opened" aria-label="Permalink to &quot;macOS says the app cannot be opened&quot;">​</a></h3><p>Unsigned builds can trigger Gatekeeper. Confirm the installer came from official GitHub Releases, then allow it from <code>System Settings -&gt; Privacy &amp; Security</code>.</p><h3 id="windows-smartscreen-shows-an-unknown-publisher-warning" tabindex="-1">Windows SmartScreen shows an unknown publisher warning <a class="header-anchor" href="#windows-smartscreen-shows-an-unknown-publisher-warning" aria-label="Permalink to &quot;Windows SmartScreen shows an unknown publisher warning&quot;">​</a></h3><p>Confirm the file came from official GitHub Releases and that the architecture in the filename matches your device. Enterprise-managed machines may require administrator approval for unsigned installers.</p><h3 id="no-traffic-appears-after-launch" tabindex="-1">No traffic appears after launch <a class="header-anchor" href="#no-traffic-appears-after-launch" aria-label="Permalink to &quot;No traffic appears after launch&quot;">​</a></h3><p>Confirm that the desktop backend is running, then check whether the system proxy is enabled and whether the target app uses the system proxy. If you configure a browser or CLI tool manually, the default proxy address is usually <code>127.0.0.1:9900</code>.</p><h3 id="https-inspection-fails" tabindex="-1">HTTPS inspection fails <a class="header-anchor" href="#https-inspection-fails" aria-label="Permalink to &quot;HTTPS inspection fails&quot;">​</a></h3><p>First confirm that the Bifrost CA is installed and trusted by the system. Some apps use certificate pinning or custom TLS stacks; exclude those apps or domains, or use rule-level <code>tlsPassthrough://</code>, instead of forcing global interception.</p><h2 id="build-from-source" tabindex="-1">Build from Source <a class="header-anchor" href="#build-from-source" aria-label="Permalink to &quot;Build from Source&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./install.sh</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./install.sh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --cli-only</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./install.sh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --desktop-only</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./install.sh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --app-dir</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/Applications</span></span></code></pre></div><p>Manual build:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clone</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/bifrost-proxy/bifrost.git</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> bifrost</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> web</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;&amp; </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;&amp; </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ..</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> desktop:build</span></span></code></pre></div><p>Build outputs are under <code>desktop/src-tauri/target/release/bundle/</code>.</p>`,49)])])}const u=s(n,[["render",o]]);export{k as __pageData,u as default};
